return $input.all().map(item => {
  const row = item.json;
  const draftPrompt = `너는 한국어 콘텐츠 초안 작성자다. 아래 승인된 콘텐츠 후보를 바탕으로 쇼츠와 블로그에 모두 쓸 수 있는 초안을 작성해라.

ContentId: ${row.ContentId}
Category: ${row.Category}
Title: ${row.Title}
Format: ${row.Format}
RiskFlag: ${row.RiskFlag}
CTA: ${row.CTA}

출력 형식은 반드시 아래 JSON만 반환해라. 마크다운 코드블록은 쓰지 마라.
{
  "DraftHook": "...",
  "DraftBody": "...",
  "DraftCTA": "...",
  "RiskReviewStatus": "LOW_RISK 또는 DISCLOSURE_REQUIRED",
  "FinalStatus": "DRAFT_READY"
}

요구사항:
1. 한국어로 작성한다.
2. 과장 수익 보장 표현은 금지한다.
3. 제휴 가능성이 있으면 고지 문구를 포함한다.
4. 실무자가 바로 읽고 쓸 수 있게 구체적으로 작성한다.`;
  return { json: { ...row, draftPrompt } };
});

return $input.all().map(item => {
  const res = item.json;
  const text = res.candidates?.[0]?.content?.parts?.[0]?.text || '';
  let parsed = {};
  try {
    parsed = JSON.parse(text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim());
  } catch (e) {
    parsed = { DraftHook: '', DraftBody: text, DraftCTA: '', RiskReviewStatus: 'REVIEW_REQUIRED', FinalStatus: 'DRAFT_READY_PARSE_FAILED' };
  }
  return { json: {
    DraftHook: parsed.DraftHook || '',
    DraftBody: parsed.DraftBody || text,
    DraftCTA: parsed.DraftCTA || '',
    RiskReviewStatus: parsed.RiskReviewStatus || 'REVIEW_REQUIRED',
    GeneratedAt: new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' }),
    FinalStatus: parsed.FinalStatus || 'DRAFT_READY'
  } };
});
